arguments.file_text:
namespace sv_3d6ac78247d54f6e82077d10f4ec47e1.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard d-flex">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content flex-grow-1 p-4">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

@using sv_3d6ac78247d54f6e82077d10f4ec47e1.Services
@inject ISettingsService SettingsService

<h3>Profile</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <div class="mb-4 d-flex align-items-center gap-3">
        <div class="avatar-preview rounded-circle bg-secondary d-flex align-items-center justify-content-center"
             style="width: 80px; height: 80px; overflow: hidden;">
            @if (!string.IsNullOrEmpty(_avatarUrl))
            {
                <img src="@_avatarUrl" alt="Avatar" style="width: 100%; height: 100%; object-fit: cover;" />
            }
            else
            {
                <span class="text-white fs-4">👤</span>
            }
        </div>
        <div class="text-muted small">@_avatarUrl</div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="_displayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="_email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="_bio"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade show" role="alert">
            Profile saved successfully!
        </div>
    }
}

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

@using sv_3d6ac78247d54f6e82077d10f4ec47e1.Services
@inject ISettingsService SettingsService

<h3>Notifications</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5>Muted Channels</h5>
    <div class="mb-4">
        @foreach (var channel in _allChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3">Preferences saved!</div>
    }
}

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_3d6ac78247d54f6e82077d10f4ec47e1.Services
@inject ISettingsService SettingsService

<h3>Security</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <!-- Change Password Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span>Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>
                @if (!string.IsNullOrEmpty(_passwordError))
                {
                    <div class="alert alert-danger">@_passwordError</div>
                }
                @if (_passwordSuccess)
                {
                    <div class="alert alert-success">Password updated successfully!</div>
                }
                <button class="btn btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <h5>Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session != _sessions.FirstOrDefault())
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => ConfirmRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-info">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5);">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="RevokeSessionAsync">Revoke</button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private bool _twoFactorEnabled;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _passwordSuccess;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _passwordSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private void ConfirmRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

