    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3">Preferences saved!</div>
    }
}

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
"}

{"path": "/tmp/sv-3d6ac78247d54f6e82077d10f4ec47e1/Components/Pages/Settings/SecuritySection.razor", "file_text": "@using sv_3d6ac78247d54f6e82077d10f4ec47e1.Services
@inject ISettingsService SettingsService

<h3>Security</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <!-- Change Password Panel -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span>Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>
                @if (!string.IsNullOrEmpty(_passwordError))
                {
                    <div class="alert alert-danger">@_passwordError</div>
                }
                @if (_passwordSuccess)
                {
                    <div class="alert alert-success">Password updated successfully!</div>
                }
                <button class="btn btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <h5>Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session != _sessions.FirstOrDefault())
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => ConfirmRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-info">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5);">
            <div class="modal-dialog">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="RevokeSessionAsync">Revoke</button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private bool _twoFactorEnabled;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _passwordSuccess;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _passwordSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private void ConfirmRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task RevokeSessionAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            _sessionToRevoke = null;
        }
    }
}
"}

{"path": "/tmp/sv-3d6ac78247d54f6e82077d10f4ec47e1/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@using sv_3d6ac78247d54f6e82077d10f4ec47e1.Services
@inject ISettingsService SettingsService

<h3>Appearance</h3>

@if (_loading)
{
    <p>Loading...</p>
}
else
{
    <!-- Theme -->
    <div class="mb-4">
        <h6>Theme</h6>
        @foreach (var theme in _themes)
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                       value="@theme" checked="@(_theme == theme)"
                       @onchange="() => _theme = theme" />
                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
            </div>
        }
    </div>

    <!-- Font Size -->
    <div class="mb-4">
        <h6>Font Size</h6>
        @foreach (var size in _fontSizes)
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                       value="@size" checked="@(_fontSize == size)"
                       @onchange="() => _fontSize = size" />
                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
            </div>
        }
    </div>

    <!-- Language -->
    <div class="mb-4">
        <h6>Language</h6>
        <select class="form-select" style="max-width: 300px;" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <!-- Compact Mode -->
    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
    </div>

    <!-- Live Preview -->
    <div class="mb-4">
        <h6>Preview</h6>
        <div class="border rounded p-3" style="@PreviewStyle">
            <h5 style="@PreviewFontStyle">Sample Heading</h5>
            <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
                This is how your content will look with the selected appearance settings.
            </p>
            <button class="btn btn-sm btn-primary">Sample Button</button>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync">Save</button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3">Appearance settings saved!</div>
    }
}

@code {
    private bool _loading = true;
    private bool _showSuccess;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string PreviewStyle => _theme switch
    {
        "Dark" => "background-color: #1e1e1e; color: #e0e0e0;",
        "Light" => "background-color: #ffffff; color: #212529;",
        _ => "background-color: #f8f9fa; color: #212529;"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.25rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
"}

